// // This module implements a 4-bit register that is disabled when the enable signal is high.
module register_with_enable (
    input clk,
    input enable,
    input [3:0] d,
    output reg [3:0] q
);

    always @(posedge clk) begin
        if (enable) begin
            q <= d;
        end
    end

endmodule
